const stddevThreshold = parseFloat($env.ANOMALY_STDDEV_THRESHOLD || 2);
const rows = $input.all().map(i => i.json);
const today = new Date().toISOString().slice(0, 10);

// Group by metric
const byMetric = {};
for (const r of rows) {
  if (!byMetric[r.metric_name]) byMetric[r.metric_name] = [];
  byMetric[r.metric_name].push(r);
}

const anomalies = [];
const all_results = [];

for (const [metric, data] of Object.entries(byMetric)) {
  const sorted = data.sort((a, b) => a.date < b.date ? -1 : 1);
  const latest = sorted[sorted.length - 1];
  if (!latest || latest.date !== today) continue;
  const window14 = sorted.slice(-15, -1); // last 14 before today
  if (window14.length < 5) continue;
  const vals = window14.map(r => parseFloat(r.value || 0));
  const mean = vals.reduce((s, v) => s + v, 0) / vals.length;
  const variance = vals.reduce((s, v) => s + Math.pow(v - mean, 2), 0) / vals.length;
  const stddev = Math.sqrt(variance);
  const today_val = parseFloat(latest.value || 0);
  const z = stddev > 0 ? Math.abs((today_val - mean) / stddev) : 0;
  const is_anomaly = z >= stddevThreshold;
  const direction = today_val > mean ? 'spike' : 'drop';
  const result = { metric, today_value: today_val, mean_14d: Math.round(mean * 100) / 100, stddev_14d: Math.round(stddev * 100) / 100, z_score: Math.round(z * 100) / 100, is_anomaly, direction, pct_from_mean: mean > 0 ? ((today_val - mean) / mean * 100).toFixed(1) : null };
  all_results.push(result);
  if (is_anomaly) anomalies.push(result);
}

return [{ json: { date: today, checked_metrics: all_results.length, anomaly_count: anomalies.length, anomalies, all_results, threshold_stddevs: stddevThreshold } }];

